            <form onSubmit={handleStaffSubmit} className="space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Full Name</label>
                  <input required placeholder="E.g. Jane Doe" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-semibold outline-none focus:border-indigo-500" value={newStaff.name} onChange={e => setNewStaff({...newStaff, name: e.target.value})} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">School Role</label>
                  <input required placeholder="E.g. Class Teacher" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-semibold outline-none focus:border-indigo-500" value={newStaff.role} onChange={e => setNewStaff({...newStaff, role: e.target.value})} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Phone Number</label>
                  <input required placeholder="E.g. +233..." className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-semibold outline-none focus:border-indigo-500" value={newStaff.phone} onChange={e => setNewStaff({...newStaff, phone: e.target.value})} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Email Address</label>
                  <input required type="email" placeholder="E.g. name@school.com" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-semibold outline-none focus:border-indigo-500" value={newStaff.email} onChange={e => setNewStaff({...newStaff, email: e.target.value})} />
                </div>
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Add to Staff Hub</button>
            </form>
          </div>
        </div>
      )}

      {isTaskModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center bg-slate-900/40 backdrop-blur-sm p-0 sm:p-4">
          <div className="bg-white rounded-t-3xl sm:rounded-3xl shadow-2xl w-full max-w-md p-6 md:p-10 animate-modalIn relative">
            <button onClick={() => setIsTaskModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-900"><X size={20} /></button>
            <div className="mb-8">
              <h2 className="text-xl font-black text-slate-800">New Activity</h2>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest mt-1">Calendar & Ops</p>
            </div>
            <form onSubmit={handleTaskSubmit} className="space-y-5">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Activity Description</label>
                <input required placeholder="What needs to be done?" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-semibold" value={newTask.title} onChange={e => setNewTask({...newTask, title: e.target.value})} />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Due Date</label>
                <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-semibold" value={newTask.dueDate} onChange={e => setNewTask({...newTask, dueDate: e.target.value})} />
              </div>
              <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black text-lg">Schedule Task</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

