  AlertTriangle,
  BrainCircuit,
  Calculator,
  ArrowDownRight,
  Coins,
  TrendingDown,
  Menu,
  Navigation
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { AppTab, Expense, Income, InventoryItem, Task, StaffRecord, BusSchedule, Policy } from './types';
import { MOCK_EXPENSES, MOCK_INVENTORY, MOCK_TASKS, MOCK_STAFF, MOCK_BUS, MOCK_POLICIES } from './constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';

// Helper for localStorage
const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    const saved = localStorage.getItem(`pb_portal_${key}`);
    return saved ? JSON.parse(saved) : defaultValue;
  },
  set: <T,>(key: string, value: T): void => {
    localStorage.setItem(`pb_portal_${key}`, JSON.stringify(value));
  }
};

// Components
const SidebarItem: React.FC<{ 
  icon: React.ElementType; 
  label: string; 
  active: boolean; 
  onClick: () => void 
}> = ({ icon: Icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center space-x-3 px-4 py-3.5 rounded-xl transition-all duration-200 ${
      active 
        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
        : 'text-slate-500 hover:bg-slate-100'
    }`}
  >
    <Icon size={20} />
    <span className="font-semibold text-sm">{label}</span>
  </button>
);

const StatCard: React.FC<{ icon: React.ElementType; label: string; value: string; color: string }> = ({ icon: Icon, label, value, color }) => (
  <div className="bg-white p-5 md:p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center space-x-4">
    <div className={`p-3.5 rounded-xl ${color} bg-opacity-10 text-${color.split('-')[1]}-600`}>
      <Icon size={24} />
    </div>
    <div className="min-w-0">
      <p className="text-slate-500 text-[10px] md:text-xs font-bold uppercase tracking-widest truncate">{label}</p>
      <h3 className="text-xl md:text-2xl font-black text-slate-800 truncate">{value}</h3>
    </div>
  </div>
);

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persisted States
  const [expenses, setExpenses] = useState<Expense[]>(() => storage.get('expenses', MOCK_EXPENSES));
  const [income, setIncome] = useState<Income[]>(() => storage.get('income', []));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => storage.get('inventory', MOCK_INVENTORY));
  const [tasks, setTasks] = useState<Task[]>(() => storage.get('tasks', MOCK_TASKS));
  const [staff, setStaff] = useState<StaffRecord[]>(() => storage.get('staff', MOCK_STAFF));
  const [busSchedules, setBusSchedules] = useState<BusSchedule[]>(() => storage.get('busSchedules', MOCK_BUS));

  // Sync with storage
  useEffect(() => storage.set('expenses', expenses), [expenses]);
  useEffect(() => storage.set('income', income), [income]);
  useEffect(() => storage.set('inventory', inventory), [inventory]);
  useEffect(() => storage.set('tasks', tasks), [tasks]);
  useEffect(() => storage.set('staff', staff), [staff]);
  useEffect(() => storage.set('busSchedules', busSchedules), [busSchedules]);

  // Modals & Panels
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);
  const [isIncomeModalOpen, setIsIncomeModalOpen] = useState(false);
  const [isCalculatorOpen, setIsCalculatorOpen] = useState(false);
  const [isTransportModalOpen, setIsTransportModalOpen] = useState(false);

  // Form States
  const [newExpense, setNewExpense] = useState<Omit<Expense, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    category: 'Operational',
    description: '',
    amount: 0
  });

  const [newIncome, setNewIncome] = useState<Omit<Income, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    source: 'School Fees',
    amount: 0
  });

  const [newStaff, setNewStaff] = useState({
    name: '',
    role: '',
    phone: '',
    email: ''
  });

  const [newTask, setNewTask] = useState<Omit<Task, 'id' | 'completed'>>({
    title: '',
    dueDate: new Date().toISOString().split('T')[0],
    priority: 'Medium'
  });

  const [newRoute, setNewRoute] = useState<Omit<BusSchedule, 'id'>>({
    busNumber: '',
    route: '',
    pickupTime: '',
    driver: {
      name: '',
      phone: '',
      homeAddress: '',
      agencyDetails: ''
    }
  });

  // Calculator State
  const [calcDisplay, setCalcDisplay] = useState('0');
  const [calcBuffer, setCalcBuffer] = useState<number | null>(null);
  const [calcOp, setCalcOp] = useState<string | null>(null);

  // Financial Calculations
  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const totalIncome = useMemo(() => income.reduce((acc, curr) => acc + curr.amount, 0), [income]);
  const netProfit = totalIncome - totalExpenses;
  const isProfitable = netProfit > 0;
  const progressPercent = totalIncome > 0 ? (netProfit / totalIncome) * 100 : 0;

  const pendingTasks = useMemo(() => tasks.filter(t => !t.completed).length, [tasks]);
  const itemsNeeded = useMemo(() => inventory.filter(i => i.needed).length, [inventory]);

  const handleExpenseSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setExpenses([...expenses, { ...newExpense, id: Date.now().toString() }]);
    setIsExpenseModalOpen(false);
    setNewExpense({ date: new Date().toISOString().split('T')[0], category: 'Operational', description: '', amount: 0 });
  };

  const handleIncomeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIncome([...income, { ...newIncome, id: Date.now().toString() }]);
    setIsIncomeModalOpen(false);
    setNewIncome({ date: new Date().toISOString().split('T')[0], source: 'School Fees', amount: 0 });
  };

  const handleStaffSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const staffMember: StaffRecord = {
      ...newStaff,
      id: Date.now().toString(),
      joiningDate: new Date().toISOString().split('T')[0],
      agreementSigned: false,
      guarantor: { name: '', phone: '', address: '' }
    };
    setStaff([...staff, staffMember]);
    setIsStaffModalOpen(false);
    setNewStaff({ name: '', role: '', phone: '', email: '' });
  };

  const handleTaskSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setTasks([...tasks, { ...newTask, id: Date.now().toString(), completed: false }]);
    setIsTaskModalOpen(false);
    setNewTask({ title: '', dueDate: new Date().toISOString().split('T')[0], priority: 'Medium' });
  };

  const handleTransportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setBusSchedules([...busSchedules, { ...newRoute, id: Date.now().toString() }]);
    setIsTransportModalOpen(false);
    setNewRoute({
      busNumber: '',
      route: '',
      pickupTime: '',
      driver: { name: '', phone: '', homeAddress: '', agencyDetails: '' }
    });
  };

  const handleCalcAction = (val: string) => {
    if (val === 'C') {
      setCalcDisplay('0');
      setCalcBuffer(null);
      setCalcOp(null);
    } else if (['+', '-', '*', '/'].includes(val)) {
      setCalcBuffer(parseFloat(calcDisplay));
      setCalcOp(val);
      setCalcDisplay('0');
    } else if (val === '=') {
      if (calcBuffer !== null && calcOp) {
        const current = parseFloat(calcDisplay);
        let result = 0;
        if (calcOp === '+') result = calcBuffer + current;
        if (calcOp === '-') result = calcBuffer - current;
        if (calcOp === '*') result = calcBuffer * current;
        if (calcOp === '/') result = calcBuffer / current;
        setCalcDisplay(result.toString());
        setCalcBuffer(null);
        setCalcOp(null);
      }
    } else {
      setCalcDisplay(calcDisplay === '0' ? val : calcDisplay + val);
    }
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  const renderCalculator = () => (
    <div className="bg-slate-900 p-6 rounded-3xl shadow-2xl w-full md:w-72 animate-fadeIn border border-slate-800">
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-white font-bold text-xs uppercase tracking-widest">School Calc</h3>
        <button onClick={() => setIsCalculatorOpen(false)} className="text-slate-400 hover:text-white"><X size={18} /></button>
      </div>
      <div className="bg-slate-800 p-4 rounded-xl mb-4 text-right overflow-hidden">
        <p className="text-indigo-400 text-[10px] font-bold h-4 truncate">{calcBuffer !== null ? `${calcBuffer} ${calcOp}` : ''}</p>
        <p className="text-white text-3xl font-black truncate">{calcDisplay}</p>
      </div>
      <div className="grid grid-cols-4 gap-2">
        {['7','8','9','/','4','5','6','*','1','2','3','-','0','.','=','+','C'].map(btn => (
          <button 
            key={btn}
            onClick={() => handleCalcAction(btn)}
            className={`h-12 rounded-xl text-sm font-bold transition-all ${
              ['/','*','-','+','='].includes(btn) ? 'bg-indigo-600 text-white hover:bg-indigo-500' :
              btn === 'C' ? 'bg-rose-500 text-white col-span-4' : 'bg-slate-700 text-slate-200 hover:bg-slate-600'
            }`}
          >
            {btn}
          </button>
        ))}
      </div>
    </div>
  );

  const renderExpenses = () => (
    <div className="space-y-6 animate-fadeIn pb-10">
      {/* Financial Health Summary */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col justify-between h-full">
          <div>
            <p className="text-xs font-black text-slate-400 uppercase tracking-widest mb-1">Financial Progress</p>
            <h3 className={`text-2xl md:text-3xl font-black ${isProfitable ? 'text-emerald-600' : 'text-rose-600'}`}>
              {isProfitable ? '+' : ''}₦{netProfit.toLocaleString()}
            </h3>
            <p className="text-xs text-slate-500 mt-2 font-medium">
              School status: <span className={`font-black ${isProfitable ? 'text-emerald-500' : 'text-rose-500'}`}>
                {isProfitable ? 'Profitable' : 'Deficit'}
              </span>
            </p>
          </div>
          <div className="mt-6">
            <div className="flex justify-between text-[10px] font-bold text-slate-400 mb-1">
              <span>PROFITABILITY</span>
              <span>{progressPercent.toFixed(1)}%</span>
            </div>
            <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ${isProfitable ? 'bg-emerald-500' : 'bg-rose-500'}`} 
                style={{ width: `${Math.min(Math.max(progressPercent, 5), 100)}%` }} 
              />
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center space-x-4">
           <div className="p-4 bg-emerald-50 text-emerald-600 rounded-2xl"><Coins size={32} /></div>
           <div className="min-w-0">
             <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Income</p>
             <h3 className="text-xl md:text-2xl font-black text-slate-800 truncate">₦{totalIncome.toLocaleString()}</h3>
             <button onClick={() => setIsIncomeModalOpen(true)} className="text-[10px] font-bold text-indigo-600 mt-1 flex items-center hover:underline whitespace-nowrap">
               <Plus size={12} className="mr-1" /> New Revenue
             </button>
           </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center space-x-4 md:col-span-2 lg:col-span-1">
           <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl"><TrendingDown size={32} /></div>
           <div className="min-w-0">
             <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Total Expenses</p>
             <h3 className="text-xl md:text-2xl font-black text-slate-800 truncate">₦{totalExpenses.toLocaleString()}</h3>
             <button onClick={() => setIsExpenseModalOpen(true)} className="text-[10px] font-bold text-rose-600 mt-1 flex items-center hover:underline whitespace-nowrap">
               <Plus size={12} className="mr-1" /> New Expense
             </button>
           </div>
        </div>
      </div>

      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="flex items-center space-x-4 w-full sm:w-auto">
          <button 
            onClick={() => setIsCalculatorOpen(!isCalculatorOpen)} 
            className={`p-3 rounded-xl transition-all ${isCalculatorOpen ? 'bg-slate-900 text-white' : 'bg-white border border-slate-100 text-slate-500 hover:text-indigo-600'}`}
          >
            <Calculator size={20} />
          </button>
          {isCalculatorOpen && (
            <div className="fixed inset-x-4 bottom-24 sm:absolute sm:inset-auto sm:mt-16 z-50">
              {renderCalculator()}
            </div>
          )}
        </div>
        <div className="flex space-x-3 w-full sm:w-auto">
          <button 
            onClick={() => setIsIncomeModalOpen(true)}
            className="flex-1 sm:flex-none px-4 py-3 bg-emerald-600 text-white rounded-xl text-xs md:text-sm font-black shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all flex items-center justify-center"
          >
            <Plus size={18} className="mr-1.5 md:mr-2" /> Income
          </button>
          <button 
            onClick={() => setIsExpenseModalOpen(true)}
            className="flex-1 sm:flex-none px-4 py-3 bg-rose-600 text-white rounded-xl text-xs md:text-sm font-black shadow-lg shadow-rose-100 hover:bg-rose-700 transition-all flex items-center justify-center"
          >
            <Plus size={18} className="mr-1.5 md:mr-2" /> Expense
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Income Log */}
        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-5 border-b border-slate-50 bg-slate-50/50">
            <h3 className="font-black text-slate-800 text-sm flex items-center">
              <Coins size={16} className="mr-2 text-emerald-500" /> Revenue Log
            </h3>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-left text-xs min-w-[300px]">
              <thead>
                <tr className="text-slate-400 font-black uppercase tracking-widest border-b border-slate-50">
                  <th className="px-5 py-4">Date</th>
                  <th className="px-5 py-4">Source</th>
                  <th className="px-5 py-4 text-right">Amount</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {income.map(i => (
                  <tr key={i.id} className="hover:bg-emerald-50/30 transition-colors">
                    <td className="px-5 py-4 text-slate-500 whitespace-nowrap">{i.date}</td>
                    <td className="px-5 py-4 font-bold text-slate-800 whitespace-nowrap">{i.source}</td>
                    <td className="px-5 py-4 text-right font-black text-emerald-600 whitespace-nowrap">₦{i.amount.toLocaleString()}</td>
                  </tr>
                ))}
                {income.length === 0 && <tr><td colSpan={3} className="p-10 text-center text-slate-400 italic">No revenue recorded</td></tr>}
              </tbody>
            </table>
          </div>
        </div>

        {/* Expense Log */}
        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-5 border-b border-slate-50 bg-slate-50/50">
            <h3 className="font-black text-slate-800 text-sm flex items-center">
              <TrendingDown size={16} className="mr-2 text-rose-500" /> Expense Log
            </h3>
          </div>
          <div className="overflow-x-auto scrollbar-hide">
            <table className="w-full text-left text-xs min-w-[300px]">
              <thead>
                <tr className="text-slate-400 font-black uppercase tracking-widest border-b border-slate-50">
                  <th className="px-5 py-4">Date</th>
                  <th className="px-5 py-4">Type</th>
                  <th className="px-5 py-4 text-right">Amount</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {expenses.map(e => (
                  <tr key={e.id} className="hover:bg-rose-50/30 transition-colors">
                    <td className="px-5 py-4 text-slate-500 whitespace-nowrap">{e.date}</td>
                    <td className="px-5 py-4 font-bold text-slate-800 whitespace-nowrap">{e.category}</td>
                    <td className="px-5 py-4 text-right font-black text-rose-600 whitespace-nowrap">₦{e.amount.toLocaleString()}</td>
                  </tr>
                ))}
                {expenses.length === 0 && <tr><td colSpan={3} className="p-10 text-center text-slate-400 italic">No expenses recorded</td></tr>}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );

  const renderDashboard = () => (
    <div className="space-y-6 animate-fadeIn pb-10">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard icon={TrendingUp} label="Net Health" value={`₦${netProfit.toLocaleString()}`} color={isProfitable ? "bg-emerald-500" : "bg-rose-500"} />
        <StatCard icon={CheckSquare} label="Tasks" value={pendingTasks.toString()} color="bg-amber-500" />
        <StatCard icon={Package} label="Inventory" value={itemsNeeded.toString()} color="bg-indigo-500" />
        <StatCard icon={Activity} label="Staff" value={staff.length.toString()} color="bg-blue-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm min-h-[350px]">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-black text-slate-800">Financial Pulse (₦)</h2>
            <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${isProfitable ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
              {isProfitable ? 'Healthy' : 'Caution'}
            </div>
          </div>
          <div className="h-64 w-full overflow-hidden">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={expenses.slice(-8)}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="category" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.05)' }} />
                <Bar dataKey="amount" radius={[6, 6, 0, 0]}>
                  {expenses.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#4f46e5' : '#818cf8'} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col">
          <h2 className="text-lg font-black text-slate-800 mb-4">Pending Tasks</h2>
          <div className="space-y-3 flex-1 overflow-y-auto max-h-[250px] scrollbar-hide">
            {tasks.filter(t => !t.completed).length > 0 ? (
              tasks.filter(t => !t.completed).slice(0, 5).map(task => (
                <div key={task.id} className="flex items-center space-x-3 p-3.5 hover:bg-slate-50 rounded-xl transition-colors border border-transparent hover:border-slate-100 group">
                  <input 
                    type="checkbox" 
                    checked={task.completed} 
                    className="h-5 w-5 rounded-lg border-slate-300 text-indigo-600 focus:ring-0 cursor-pointer"
                    onChange={() => setTasks(tasks.map(t => t.id === task.id ? {...t, completed: !t.completed} : t))}
                  />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-bold text-slate-700 truncate">{task.title}</p>
                    <p className="text-[10px] text-slate-400 font-medium">Due: {task.dueDate}</p>
                  </div>
                </div>
              ))
            ) : (
              <div className="flex flex-col items-center justify-center py-10 opacity-40">
                <CheckSquare size={32} className="mb-2" />
                <p className="text-xs font-bold">All caught up!</p>
              </div>
            )}
          </div>
          <button onClick={() => setActiveTab(AppTab.TASKS)} className="w-full mt-4 py-3 text-xs text-indigo-600 font-black hover:bg-indigo-50 rounded-xl transition-all border border-indigo-50 uppercase tracking-widest">
            View All Activities
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-50 overflow-x-hidden font-inter relative">
      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden animate-fadeIn"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-100 flex flex-col 
        transition-transform duration-300 ease-in-out shadow-xl md:shadow-none
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:translate-x-0
      `}>
        <div className="p-6 mb-4 flex justify-between items-center">
          <div>
            <h1 className="text-xl font-black text-indigo-600 leading-tight">Princess Bilingual</h1>
            <p className="text-[10px] text-slate-400 font-black tracking-[0.2em] uppercase mt-1">Management Portal</p>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 text-slate-400 hover:text-slate-900">
            <X size={20} />
          </button>
        </div>

        <nav className="flex-1 px-4 space-y-1.5 overflow-y-auto scrollbar-hide">
          <SidebarItem icon={LayoutDashboard} label="Dashboard" active={activeTab === AppTab.DASHBOARD} onClick={() => { setActiveTab(AppTab.DASHBOARD); setIsSidebarOpen(false); }} />
          <SidebarItem icon={Wallet} label="Expenses" active={activeTab === AppTab.EXPENSES} onClick={() => { setActiveTab(AppTab.EXPENSES); setIsSidebarOpen(false); }} />
          <SidebarItem icon={Package} label="Inventory" active={activeTab === AppTab.INVENTORY} onClick={() => { setActiveTab(AppTab.INVENTORY); setIsSidebarOpen(false); }} />
          <SidebarItem icon={CheckSquare} label="Activities" active={activeTab === AppTab.TASKS} onClick={() => { setActiveTab(AppTab.TASKS); setIsSidebarOpen(false); }} />
          <SidebarItem icon={Users} label="Staff Hub" active={activeTab === AppTab.STAFF} onClick={() => { setActiveTab(AppTab.STAFF); setIsSidebarOpen(false); }} />
          <SidebarItem icon={Bus} label="Transport" active={activeTab === AppTab.TRANSPORT} onClick={() => { setActiveTab(AppTab.TRANSPORT); setIsSidebarOpen(false); }} />
          <SidebarItem icon={FileText} label="Policy Center" active={activeTab === AppTab.POLICIES} onClick={() => { setActiveTab(AppTab.POLICIES); setIsSidebarOpen(false); }} />
