                <p className="text-amber-100 text-[10px] font-black uppercase tracking-widest mt-1">Transport Logistics</p>
              </div>
              <button onClick={() => setIsTransportModalOpen(false)} className="p-2 hover:bg-white/20 rounded-xl transition-colors"><X size={24} /></button>
            </div>
            <form onSubmit={handleTransportSubmit} className="p-6 md:p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Bus Number</label>
                  <input required placeholder="E.g. PB-05" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={newRoute.busNumber} onChange={e => setNewRoute({...newRoute, busNumber: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Pickup Time</label>
                  <input required placeholder="E.g. 06:45 AM" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={newRoute.pickupTime} onChange={e => setNewRoute({...newRoute, pickupTime: e.target.value})} />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Route Name/Area</label>
                <input required placeholder="E.g. Route Gamma: East Legon Area" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={newRoute.route} onChange={e => setNewRoute({...newRoute, route: e.target.value})} />
              </div>

              <div className="pt-4 border-t border-slate-100">
                <p className="text-[10px] font-black text-indigo-500 uppercase tracking-[0.2em] mb-4">Driver Particulars</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Driver Name</label>
                    <input required placeholder="Full Name" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={newRoute.driver.name} onChange={e => setNewRoute({...newRoute, driver: {...newRoute.driver, name: e.target.value}})} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Phone Number</label>
                    <input required placeholder="+233..." className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={newRoute.driver.phone} onChange={e => setNewRoute({...newRoute, driver: {...newRoute.driver, phone: e.target.value}})} />
                  </div>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Residential Base</label>
                <input required placeholder="Driver's Home Address" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={newRoute.driver.homeAddress} onChange={e => setNewRoute({...newRoute, driver: {...newRoute.driver, homeAddress: e.target.value}})} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Agency/Contract Details</label>
                <input placeholder="E.g. Private or Agency Name" className="w-full px-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl text-sm font-bold" value={newRoute.driver.agencyDetails} onChange={e => setNewRoute({...newRoute, driver: {...newRoute.driver, agencyDetails: e.target.value}})} />
              </div>

              <button type="submit" className="w-full py-4 bg-amber-500 text-white rounded-2xl font-black text-lg shadow-xl shadow-amber-100 hover:bg-amber-600 transition-all flex items-center justify-center">
                <Navigation size={20} className="mr-3" /> Initialize Route
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  LayoutDashboard, 
  Wallet, 
  Package, 
  CheckSquare, 
  Users, 
  Bus, 
  FileText, 
  LogOut,
  Bell,
  Search,
  Plus,
  ArrowUpRight,
  TrendingUp,
  Activity,
  X,
  Save,
  Clock,
  MapPin,
  ShieldCheck,
