      </aside>

      {/* Main Content */}
      <main className={`flex-1 transition-all duration-300 w-full md:ml-64 ${isSidebarOpen ? 'blur-sm md:blur-none' : ''}`}>
        <header className="sticky top-0 z-30 bg-slate-50/80 backdrop-blur-md px-4 md:px-10 py-5 flex justify-between items-center border-b border-transparent">
          <div className="flex items-center space-x-4">
            <button onClick={toggleSidebar} className="md:hidden p-2.5 bg-white border border-slate-200 rounded-xl shadow-sm text-slate-600"><Menu size={20} /></button>
            <div className="hidden sm:block">
              <h1 className="text-xl md:text-2xl font-black text-slate-800 capitalize tracking-tight">{activeTab}</h1>
              <p className="text-slate-400 text-[10px] md:text-xs font-semibold uppercase tracking-widest">Central Command</p>
            </div>
          </div>

          <div className="flex items-center space-x-2 md:space-x-4">
            <button className="p-2.5 bg-white border border-slate-100 rounded-xl text-slate-500 relative shadow-sm">
              <Bell size={18} />
