const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persisted States
  const [expenses, setExpenses] = useState<Expense[]>(() => storage.get('expenses', MOCK_EXPENSES));
  const [income, setIncome] = useState<Income[]>(() => storage.get('income', []));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => storage.get('inventory', MOCK_INVENTORY));
  const [tasks, setTasks] = useState<Task[]>(() => storage.get('tasks', MOCK_TASKS));
  const [staff, setStaff] = useState<StaffRecord[]>(() => storage.get('staff', MOCK_STAFF));
  const [busSchedules, setBusSchedules] = useState<BusSchedule[]>(() => storage.get('busSchedules', MOCK_BUS));

  // AI States
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [aiMessages, setAiMessages] = useState<{role: 'user' | 'assistant', content: string}[]>([
    { role: 'assistant', content: 'Hello Madam Gloria. I am your school assistant. How can I help you manage Princess Bilingual today?' }
  ]);
  const [aiInput, setAiInput] = useState('');
  const [isAiTyping, setIsAiTyping] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Sync with storage
  useEffect(() => storage.set('expenses', expenses), [expenses]);
  useEffect(() => storage.set('income', income), [income]);
  useEffect(() => storage.set('inventory', inventory), [inventory]);
  useEffect(() => storage.set('tasks', tasks), [tasks]);
  useEffect(() => storage.set('staff', staff), [staff]);
  useEffect(() => storage.set('busSchedules', busSchedules), [busSchedules]);

  useEffect(() => {
    if (chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [aiMessages]);

  // Modals & Panels
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);
  const [isIncomeModalOpen, setIsIncomeModalOpen] = useState(false);
  const [isCalculatorOpen, setIsCalculatorOpen] = useState(false);
  const [isTransportModalOpen, setIsTransportModalOpen] = useState(false);

  // Form States
  const [newExpense, setNewExpense] = useState<Omit<Expense, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    category: 'Operational',
    description: '',
    amount: 0
  });

  const [newIncome, setNewIncome] = useState<Omit<Income, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    source: 'School Fees',
    amount: 0
  });

  const [newStaff, setNewStaff] = useState({ name: '', role: '', phone: '', email: '' });
  const [newTask, setNewTask] = useState<Omit<Task, 'id' | 'completed'>>({ title: '', dueDate: new Date().toISOString().split('T')[0], priority: 'Medium' });
  const [newRoute, setNewRoute] = useState<Omit<BusSchedule, 'id'>>({
    busNumber: '', route: '', pickupTime: '',
    driver: { name: '', phone: '', homeAddress: '', agencyDetails: '' }
  });

  // Calculator Logic
  const [calcDisplay, setCalcDisplay] = useState('0');
  const [calcBuffer, setCalcBuffer] = useState<number | null>(null);
  const [calcOp, setCalcOp] = useState<string | null>(null);

  // Financial Calculations
  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const totalIncome = useMemo(() => income.reduce((acc, curr) => acc + curr.amount, 0), [income]);
  const netProfit = totalIncome - totalExpenses;
  const isProfitable = netProfit >= 0;
  const progressPercent = totalIncome > 0 ? (netProfit / totalIncome) * 100 : 0;
  const pendingTasksCount = useMemo(() => tasks.filter(t => !t.completed).length, [tasks]);
  const itemsNeededCount = useMemo(() => inventory.filter(i => i.needed).length, [inventory]);

  // Actions
  const handleAiChat = async (input?: string) => {
    const text = input || aiInput;
    if (!text.trim()) return;

    const userMessage = { role: 'user' as const, content: text };
    setAiMessages(prev => [...prev, userMessage]);
    setAiInput('');
    setIsAiTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const context = {
        finances: { totalIncome, totalExpenses, netProfit },
        inventoryStatus: inventory.filter(i => i.needed).map(i => i.name),
        pendingTasks: tasks.filter(t => !t.completed).map(t => t.title),
        staffCount: staff.length
      };

      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: `You are the Princess Bilingual School AI Assistant helping Madam Gloria. Current Data: ${JSON.stringify(context)}. Keep it professional.`
        }
      });

      const result = await chat.sendMessageStream({ message: text });
      let fullResponse = "";
      setAiMessages(prev => [...prev, { role: 'assistant', content: '' }]);
      for await (const chunk of result) {
        fullResponse += chunk.text;
        setAiMessages(prev => {
          const updated = [...prev];
          updated[updated.length - 1].content = fullResponse;
          return updated;
        });
      }
    } catch (error) {
      setAiMessages(prev => [...prev, { role: 'assistant', content: 'Connection error. Please try again.' }]);
    } finally {
      setIsAiTyping(false);
    }
  };

  const handleExpenseSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newExpense.amount <= 0 || isNaN(newExpense.amount)) return;
    setExpenses(prev => [...prev, { ...newExpense, id: Date.now().toString() }]);
    setIsExpenseModalOpen(false);
    setNewExpense({ date: new Date().toISOString().split('T')[0], category: 'Operational', description: '', amount: 0 });
  };

  const handleIncomeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newIncome.amount <= 0 || isNaN(newIncome.amount)) return;
    setIncome(prev => [...prev, { ...newIncome, id: Date.now().toString() }]);
    setIsIncomeModalOpen(false);
    setNewIncome({ date: new Date().toISOString().split('T')[0], source: 'School Fees', amount: 0 });
  };

  const handleResetFinancials = () => {
    const confirmMessage = "This action will permanently turn all school income, expenses, and net profit records to Zero.\n\nAre you sure Madam Gloria?";
    if (window.confirm(confirmMessage)) {
      setExpenses([]);
      setIncome([]);
      // Force UI back to dashboard for fresh view
      setActiveTab(AppTab.DASHBOARD);
    }
  };

  const handleStaffSubmit = (e: React.FormEvent) => {
