// Helper for localStorage
const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    const saved = localStorage.getItem(`pb_portal_${key}`);
    try {
      return saved ? JSON.parse(saved) : defaultValue;
    } catch {
      return defaultValue;
    }
  },
  set: <T,>(key: string, value: T): void => {
    localStorage.setItem(`pb_portal_${key}`, JSON.stringify(value));
  }
};

// Components
const SidebarItem: React.FC<{ 
  icon: React.ElementType; 
  label: string; 
  active: boolean; 
  onClick: () => void 
}> = ({ icon: Icon, label, active, onClick }) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center space-x-3 px-4 py-3.5 rounded-xl transition-all duration-200 ${
      active 
        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' 
        : 'text-slate-500 hover:bg-slate-100'
    }`}
  >
    <Icon size={20} />
    <span className="font-semibold text-sm">{label}</span>
  </button>
);

const StatCard: React.FC<{ icon: React.ElementType; label: string; value: string; color: string }> = ({ icon: Icon, label, value, color }) => (
  <div className="bg-white p-5 md:p-6 rounded-2xl border border-slate-100 shadow-sm flex items-center space-x-4">
    <div className={`p-3.5 rounded-xl ${color} bg-opacity-10 text-${color.split('-')[1]}-600`}>
      <Icon size={24} />
    </div>
    <div className="min-w-0">
      <p className="text-slate-500 text-[10px] md:text-xs font-bold uppercase tracking-widest truncate">{label}</p>
      <h3 className="text-xl md:text-2xl font-black text-slate-800 truncate">{value}</h3>
    </div>
  </div>
);

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AppTab>(AppTab.DASHBOARD);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  // Persisted States
  const [expenses, setExpenses] = useState<Expense[]>(() => storage.get('expenses', MOCK_EXPENSES));
  const [income, setIncome] = useState<Income[]>(() => storage.get('income', []));
  const [inventory, setInventory] = useState<InventoryItem[]>(() => storage.get('inventory', MOCK_INVENTORY));
  const [tasks, setTasks] = useState<Task[]>(() => storage.get('tasks', MOCK_TASKS));
  const [staff, setStaff] = useState<StaffRecord[]>(() => storage.get('staff', MOCK_STAFF));
  const [busSchedules, setBusSchedules] = useState<BusSchedule[]>(() => storage.get('busSchedules', MOCK_BUS));

  // AI States
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [aiMessages, setAiMessages] = useState<{role: 'user' | 'assistant', content: string}[]>([
    { role: 'assistant', content: 'Hello Madam Gloria. I am your school assistant. How can I help you manage Princess Bilingual today?' }
  ]);
  const [aiInput, setAiInput] = useState('');
  const [isAiTyping, setIsAiTyping] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Sync with storage
  useEffect(() => storage.set('expenses', expenses), [expenses]);
  useEffect(() => storage.set('income', income), [income]);
  useEffect(() => storage.set('inventory', inventory), [inventory]);
  useEffect(() => storage.set('tasks', tasks), [tasks]);
  useEffect(() => storage.set('staff', staff), [staff]);
  useEffect(() => storage.set('busSchedules', busSchedules), [busSchedules]);

  useEffect(() => {
    if (chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [aiMessages]);

  // Modals & Panels
  const [isStaffModalOpen, setIsStaffModalOpen] = useState(false);
  const [isTaskModalOpen, setIsTaskModalOpen] = useState(false);
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);
  const [isIncomeModalOpen, setIsIncomeModalOpen] = useState(false);
  const [isCalculatorOpen, setIsCalculatorOpen] = useState(false);
  const [isTransportModalOpen, setIsTransportModalOpen] = useState(false);

  // Form States
  const [newExpense, setNewExpense] = useState<Omit<Expense, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    category: 'Operational',
    description: '',
    amount: 0
  });

  const [newIncome, setNewIncome] = useState<Omit<Income, 'id'>>({
    date: new Date().toISOString().split('T')[0],
    source: 'School Fees',
    amount: 0
  });

  const [newStaff, setNewStaff] = useState({ name: '', role: '', phone: '', email: '' });
  const [newTask, setNewTask] = useState<Omit<Task, 'id' | 'completed'>>({ title: '', dueDate: new Date().toISOString().split('T')[0], priority: 'Medium' });
  const [newRoute, setNewRoute] = useState<Omit<BusSchedule, 'id'>>({
    busNumber: '', route: '', pickupTime: '',
    driver: { name: '', phone: '', homeAddress: '', agencyDetails: '' }
  });

  // Calculator Logic
  const [calcDisplay, setCalcDisplay] = useState('0');
  const [calcBuffer, setCalcBuffer] = useState<number | null>(null);
  const [calcOp, setCalcOp] = useState<string | null>(null);

  // Financial Calculations
  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const totalIncome = useMemo(() => income.reduce((acc, curr) => acc + curr.amount, 0), [income]);
  const netProfit = totalIncome - totalExpenses;
  const isProfitable = netProfit >= 0;
  const progressPercent = totalIncome > 0 ? (netProfit / totalIncome) * 100 : 0;
  const pendingTasksCount = useMemo(() => tasks.filter(t => !t.completed).length, [tasks]);
  const itemsNeededCount = useMemo(() => inventory.filter(i => i.needed).length, [inventory]);

  // Actions
  const handleAiChat = async (input?: string) => {
    const text = input || aiInput;
    if (!text.trim()) return;

    const userMessage = { role: 'user' as const, content: text };
    setAiMessages(prev => [...prev, userMessage]);
    setAiInput('');
    setIsAiTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const context = {
        finances: { totalIncome, totalExpenses, netProfit },
        inventoryStatus: inventory.filter(i => i.needed).map(i => i.name),
        pendingTasks: tasks.filter(t => !t.completed).map(t => t.title),
        staffCount: staff.length
      };

      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: `You are the Princess Bilingual School AI Assistant helping Madam Gloria. Current Data: ${JSON.stringify(context)}. Keep it professional.`
        }
      });

      const result = await chat.sendMessageStream({ message: text });
      let fullResponse = "";
      setAiMessages(prev => [...prev, { role: 'assistant', content: '' }]);
      for await (const chunk of result) {
        fullResponse += chunk.text;
        setAiMessages(prev => {
          const updated = [...prev];
          updated[updated.length - 1].content = fullResponse;
          return updated;
        });
      }
    } catch (error) {
      setAiMessages(prev => [...prev, { role: 'assistant', content: 'Connection error. Please try again.' }]);
    } finally {
      setIsAiTyping(false);
    }
  };

  const handleExpenseSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newExpense.amount <= 0 || isNaN(newExpense.amount)) return;
    setExpenses(prev => [...prev, { ...newExpense, id: Date.now().toString() }]);
    setIsExpenseModalOpen(false);
    setNewExpense({ date: new Date().toISOString().split('T')[0], category: 'Operational', description: '', amount: 0 });
  };

  const handleIncomeSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newIncome.amount <= 0 || isNaN(newIncome.amount)) return;
    setIncome(prev => [...prev, { ...newIncome, id: Date.now().toString() }]);
    setIsIncomeModalOpen(false);
    setNewIncome({ date: new Date().toISOString().split('T')[0], source: 'School Fees', amount: 0 });
  };

  const handleResetFinancials = () => {
    const confirmMessage = "URGENT ACTION: This will PERMANENTLY ERASE all income, expenses, and profit history, turning everything to Zero.\n\nProceed Madam Gloria?";
    if (window.confirm(confirmMessage)) {
      // Set states to empty arrays instantly
      setExpenses([]);
      setIncome([]);
      // Clear localStorage specifically for these
      localStorage.removeItem('pb_portal_expenses');
      localStorage.removeItem('pb_portal_income');

      alert("Success: All financial records have been reset to Zero.");
    }
  };

  const handleStaffSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setStaff([...staff, { ...newStaff, id: Date.now().toString(), joiningDate: new Date().toISOString().split('T')[0], agreementSigned: false, guarantor: { name: '', phone: '', address: '' } }]);
    setIsStaffModalOpen(false);
    setNewStaff({ name: '', role: '', phone: '', email: '' });
  };

  const handleTaskSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setTasks([...tasks, { ...newTask, id: Date.now().toString(), completed: false }]);
    setIsTaskModalOpen(false);
    setNewTask({ title: '', dueDate: new Date().toISOString().split('T')[0], priority: 'Medium' });
  };

  const handleTransportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setBusSchedules([...busSchedules, { ...newRoute, id: Date.now().toString() }]);
    setIsTransportModalOpen(false);
    setNewRoute({ busNumber: '', route: '', pickupTime: '', driver: { name: '', phone: '', homeAddress: '', agencyDetails: '' } });
  };

  const handleCalcAction = (val: string) => {
    if (val === 'C') { setCalcDisplay('0'); setCalcBuffer(null); setCalcOp(null); }
    else if (['+', '-', '*', '/'].includes(val)) { setCalcBuffer(parseFloat(calcDisplay)); setCalcOp(val); setCalcDisplay('0'); }
    else if (val === '=') {
      if (calcBuffer !== null && calcOp) {
        const current = parseFloat(calcDisplay);
        let result = 0;
        if (calcOp === '+') result = calcBuffer + current;
        if (calcOp === '-') result = calcBuffer - current;
        if (calcOp === '*') result = calcBuffer * current;
        if (calcOp === '/') result = calcBuffer / current;
        setCalcDisplay(result.toString()); setCalcBuffer(null); setCalcOp(null);
      }
    } else { setCalcDisplay(calcDisplay === '0' ? val : calcDisplay + val); }
  };

  const toggleSidebar = () => setIsSidebarOpen(!isSidebarOpen);

  // Layout Renders
  const renderDashboard = () => (
    <div className="space-y-6 animate-fadeIn pb-10">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          icon={TrendingUp} 
          label="Net Profit" 
          value={`₦${netProfit.toLocaleString()}`} 
          color={isProfitable && netProfit > 0 ? "bg-emerald-500" : (netProfit < 0 ? "bg-rose-500" : "bg-slate-500")} 
        />
        <StatCard icon={CheckSquare} label="Tasks" value={pendingTasksCount.toString()} color="bg-amber-500" />
        <StatCard icon={Package} label="Inventory" value={itemsNeededCount.toString()} color="bg-indigo-500" />
        <StatCard icon={Activity} label="Staff" value={staff.length.toString()} color="bg-blue-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-slate-100 shadow-sm min-h-[350px]">
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-lg font-black text-slate-800">Financial Pulse</h2>
            <div className={`px-3 py-1 rounded-full text-[10px] font-black uppercase ${netProfit > 0 ? 'bg-emerald-50 text-emerald-600' : (netProfit < 0 ? 'bg-rose-50 text-rose-600' : 'bg-slate-50 text-slate-600')}`}>
              {netProfit > 0 ? 'Surplus' : (netProfit < 0 ? 'Deficit' : 'Balanced')}
            </div>
          </div>
          <div className="h-64 w-full">
            {(expenses.length > 0 || income.length > 0) ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={expenses.length > 0 ? expenses.slice(-8) : [{ category: 'No Expenses', amount: 0 }]}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="category" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                  <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.05)' }} />
                  <Bar dataKey="amount" radius={[6, 6, 0, 0]}>
                    {expenses.length > 0 ? expenses.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#4f46e5' : '#818cf8'} />
                    )) : [<Cell key="cell-0" fill="#e2e8f0" />]}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex flex-col items-center justify-center text-slate-300 opacity-60">
                <div className="p-5 bg-slate-50 rounded-full mb-4">
                   <TrendingDown size={48} className="text-slate-200" />
                </div>
                <p className="text-xs font-black uppercase tracking-widest text-slate-400">Financial records are empty (₦0)</p>
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-black text-slate-800">Urgent Activities</h2>
            <div className="bg-indigo-50 text-indigo-600 p-1.5 rounded-lg"><Clock size={16} /></div>
          </div>
          <div className="space-y-3 flex-1 overflow-y-auto max-h-[250px] scrollbar-hide">
            {tasks.filter(t => !t.completed).length > 0 ? (
              tasks.filter(t => !t.completed).slice(0, 5).map(task => (
                <div key={task.id} className="flex items-center space-x-3 p-3.5 hover:bg-slate-50 rounded-xl transition-colors border border-transparent hover:border-slate-100">
                  <input 
                    type="checkbox" 
                    checked={task.completed} 
                    className="h-5 w-5 rounded-lg border-slate-300 text-indigo-600 focus:ring-0 cursor-pointer"
                    onChange={() => setTasks(tasks.map(t => t.id === task.id ? {...t, completed: !t.completed} : t))}
                  />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-bold text-slate-700 truncate">{task.title}</p>
                    <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Due {task.dueDate}</p>
                  </div>
                </div>
              ))
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-slate-300">
                <CheckCircle2 size={40} className="mb-2 opacity-20" />
                <p className="text-xs font-black uppercase tracking-widest text-slate-400">All tasks completed</p>
              </div>
