        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-40 md:hidden animate-fadeIn" onClick={() => setIsSidebarOpen(false)} />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-100 flex flex-col transition-transform duration-300 ease-in-out shadow-xl md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0`}>
        <div className="p-6 mb-4 flex justify-between items-center">
          <div>
            <h1 className="text-xl font-black text-indigo-600 leading-tight">Princess Bilingual</h1>
            <p className="text-[10px] text-slate-400 font-black tracking-[0.2em] uppercase mt-1">Management Portal</p>
