                <p className="text-[10px] opacity-80 uppercase tracking-[0.2em] font-black mt-1">School Fees & Revenue</p>
              </div>
              <button onClick={() => setIsIncomeModalOpen(false)} className="relative z-10 p-2 hover:bg-white/20 rounded-2xl transition-colors"><X size={24} /></button>
            </div>
            <form onSubmit={handleIncomeSubmit} className="p-8 space-y-6">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Credit Amount (₦)</label>
                <input 
                  required 
                  type="number" 
                  step="0.01" 
                  autoFocus
                  value={newIncome.amount || ''} 
                  onChange={e => {
                    const val = parseFloat(e.target.value);
                    setNewIncome({...newIncome, amount: isNaN(val) ? 0 : val});
                  }} 
                  className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl text-3xl font-black outline-none focus:border-emerald-500 transition-all text-slate-800" 
                  placeholder="0.00" 
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Source</label>
                  <select value={newIncome.source} onChange={e => setNewIncome({...newIncome, source: e.target.value})} className="w-full px-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold appearance-none">
                    <option value="School Fees">School Fees</option><option value="Admission">Admission</option><option value="Uniforms">Uniforms</option><option value="Books">Books</option><option value="Donation">Donation</option><option value="Transport">Transport Fee</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2">Date</label>
                  <input required type="date" value={newIncome.date} onChange={e => setNewIncome({...newIncome, date: e.target.value})} className="w-full px-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold" />
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-emerald-600 text-white rounded-3xl font-black text-lg shadow-xl shadow-emerald-100 flex items-center justify-center hover:bg-emerald-700 transition-all active:scale-95">
                <Save size={20} className="mr-3" /> Log Credit
              </button>
            </form>
          </div>
        </div>
      )}

      {isCalculatorOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="max-w-xs w-full animate-modalIn relative">
            <button onClick={() => setIsCalculatorOpen(false)} className="absolute -top-12 right-0 p-3 text-white bg-slate-900 rounded-full shadow-xl hover:scale-110 transition-transform"><X size={20} /></button>
            <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl border border-slate-800">
              <div className="flex justify-between items-center mb-6">
                 <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">School Treasury Calc</p>
                 <Calculator size={16} className="text-slate-500" />
              </div>
              <div className="bg-slate-800 p-6 rounded-2xl mb-6 text-right overflow-hidden shadow-inner min-h-[100px] flex flex-col justify-center">
                <p className="text-indigo-400 text-[10px] font-bold h-4 truncate">{calcBuffer !== null ? `${calcBuffer} ${calcOp}` : ''}</p>
                <p className="text-white text-4xl font-black truncate">{calcDisplay}</p>
              </div>
              <div className="grid grid-cols-4 gap-3">
                {['7','8','9','/','4','5','6','*','1','2','3','-','0','.','=','+','C'].map(btn => (
                  <button 
                    key={btn} 
                    onClick={() => handleCalcAction(btn)} 
                    className={`h-14 rounded-2xl text-sm font-black transition-all active:scale-95 ${
                      ['/','*','-','+','='].includes(btn) 
                        ? 'bg-indigo-600 text-white hover:bg-indigo-500' 
                        : btn === 'C' 
                          ? 'bg-rose-500 text-white col-span-4' 
                          : 'bg-slate-700 text-slate-200 hover:bg-slate-600'
                    }`}
                  >
                    {btn}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Floating AI Bubble */}
      <button 
        onClick={() => setIsAiOpen(true)} 
        className={`fixed bottom-8 right-8 z-40 p-6 bg-indigo-600 text-white rounded-full shadow-2xl shadow-indigo-200 hover:scale-110 active:scale-95 transition-all group ${isAiOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}
      >
        <Zap size={32} className="animate-pulse group-hover:animate-none" />
      </button>

      {/* Modal Placeholders for Staff, Tasks, Transport (previously implemented) */}
      {isStaffModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 p-4">
          <div className="bg-white p-10 rounded-[2.5rem] w-full max-w-md animate-modalIn relative">
            <button onClick={() => setIsStaffModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-900"><X size={24} /></button>
            <div className="mb-8">
               <h2 className="text-2xl font-black text-slate-800">Register Staff</h2>
               <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">HR Hub</p>
            </div>
            <form onSubmit={handleStaffSubmit} className="space-y-4">
              <input required placeholder="Staff Full Name" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newStaff.name} onChange={e => setNewStaff({...newStaff, name: e.target.value})} />
              <input required placeholder="Designation" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newStaff.role} onChange={e => setNewStaff({...newStaff, role: e.target.value})} />
              <input required placeholder="Contact Phone" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newStaff.phone} onChange={e => setNewStaff({...newStaff, phone: e.target.value})} />
              <input required placeholder="Email" type="email" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newStaff.email} onChange={e => setNewStaff({...newStaff, email: e.target.value})} />
              <button type="submit" className="w-full py-5 mt-4 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase tracking-widest shadow-xl">Register Member</button>
            </form>
          </div>
        </div>
      )}

      {isTaskModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 p-4">
          <div className="bg-white p-10 rounded-[2.5rem] w-full max-w-md animate-modalIn">
            <div className="flex justify-between items-center mb-8"><h2 className="text-2xl font-black">New Task</h2><button onClick={() => setIsTaskModalOpen(false)}><X size={24} /></button></div>
            <form onSubmit={handleTaskSubmit} className="space-y-4">
              <input required placeholder="Description" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newTask.title} onChange={e => setNewTask({...newTask, title: e.target.value})} />
              <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newTask.dueDate} onChange={e => setNewTask({...newTask, dueDate: e.target.value})} />
              <button type="submit" className="w-full py-5 mt-4 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase shadow-xl">Create Entry</button>
            </form>
          </div>
        </div>
      )}

      {isTransportModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 p-4">
          <div className="bg-white p-10 rounded-[2.5rem] w-full max-w-md animate-modalIn overflow-y-auto max-h-[90vh] relative">
            <button onClick={() => setIsTransportModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-900"><X size={24} /></button>
            <div className="mb-8"><h2 className="text-2xl font-black">Add Route</h2></div>
            <form onSubmit={handleTransportSubmit} className="space-y-4">
              <input required placeholder="Bus ID" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newRoute.busNumber} onChange={e => setNewRoute({...newRoute, busNumber: e.target.value})} />
              <input required placeholder="Route Area" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newRoute.route} onChange={e => setNewRoute({...newRoute, route: e.target.value})} />
              <input required placeholder="Pickup Time" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newRoute.pickupTime} onChange={e => setNewRoute({...newRoute, pickupTime: e.target.value})} />
              <div className="p-5 bg-indigo-50/50 rounded-2xl border border-indigo-100">
                <input required placeholder="Driver Name" className="w-full p-3 mb-3 bg-white rounded-xl border border-indigo-100 font-bold text-sm" value={newRoute.driver.name} onChange={e => setNewRoute({...newRoute, driver: {...newRoute.driver, name: e.target.value}})} />
                <input required placeholder="Driver Contact" className="w-full p-3 bg-white rounded-xl border border-indigo-100 font-bold text-sm" value={newRoute.driver.phone} onChange={e => setNewRoute({...newRoute, driver: {...newRoute.driver, phone: e.target.value}})} />
              </div>
              <button type="submit" className="w-full py-5 mt-2 bg-amber-500 text-white rounded-[1.5rem] font-black uppercase shadow-xl shadow-amber-100 transition-all active:scale-95">Initialize Dispatch</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

