            <form onSubmit={(e) => { e.preventDefault(); setIncome(prev => [...prev, { ...newIncome, id: Date.now().toString() }]); setIsIncomeModalOpen(false); }} className="p-8 space-y-6">
              <input type="number" step="0.01" value={newIncome.amount || ''} onChange={e => setNewIncome({...newIncome, amount: parseFloat(e.target.value) || 0})} className="w-full px-6 py-5 bg-slate-50 border-2 border-slate-100 rounded-3xl text-3xl font-black outline-none focus:border-emerald-500" placeholder="₦0.00" required />
              <select value={newIncome.source} onChange={e => setNewIncome({...newIncome, source: e.target.value})} className="w-full px-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold">
                <option value="School Fees">School Fees</option><option value="Admission">Admission</option><option value="Uniforms">Uniforms</option>
              </select>
              <button type="submit" className="w-full py-5 bg-emerald-600 text-white rounded-3xl font-black text-lg active:scale-95">Log Revenue</button>
