      {isCalculatorOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4">
          <div className="max-w-xs w-full animate-modalIn relative">
            <button onClick={() => setIsCalculatorOpen(false)} className="absolute -top-12 right-0 p-3 text-white bg-slate-900 rounded-full shadow-xl"><X size={20} /></button>
            <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl border border-slate-800">
              <div className="bg-slate-800 p-6 rounded-2xl mb-6 text-right shadow-inner min-h-[100px] flex flex-col justify-center">
                <p className="text-indigo-400 text-[10px] font-bold h-4 truncate">{calcBuffer !== null ? `${calcBuffer} ${calcOp}` : ''}</p>
                <p className="text-white text-4xl font-black truncate">{calcDisplay}</p>
              </div>
              <div className="grid grid-cols-4 gap-3">
                {['7','8','9','/','4','5','6','*','1','2','3','-','0','.','=','+','C'].map(btn => (
                  <button key={btn} onClick={() => handleCalcAction(btn)} className={`h-14 rounded-2xl text-sm font-black transition-all active:scale-95 ${['/','*','-','+','='].includes(btn) ? 'bg-indigo-600 text-white' : btn === 'C' ? 'bg-rose-500 text-white col-span-4' : 'bg-slate-700 text-slate-200'}`}>{btn}</button>
                ))}
              </div>
