            <form onSubmit={(e) => { e.preventDefault(); setTasks([...tasks, { ...newTask, id: Date.now().toString(), completed: false }]); setIsTaskModalOpen(false); }} className="space-y-4">
              <input required placeholder="Description" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newTask.title} onChange={e => setNewTask({...newTask, title: e.target.value})} />
              <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newTask.dueDate} onChange={e => setNewTask({...newTask, dueDate: e.target.value})} />
              <button type="submit" className="w-full py-5 mt-4 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase shadow-xl">Create Entry</button>
            </form>
          </div>
        </div>
      )}

      {isStaffModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 p-4">
          <div className="bg-white p-10 rounded-[2.5rem] w-full max-w-md animate-modalIn relative">
            <button onClick={() => setIsStaffModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-900"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-800 mb-8">Register Personnel</h2>
            <form onSubmit={(e) => { e.preventDefault(); setStaff([...staff, { ...newStaff, id: Date.now().toString(), joiningDate: new Date().toISOString().split('T')[0], agreementSigned: false, guarantor: { name: '', phone: '', address: '' } }]); setIsStaffModalOpen(false); }} className="space-y-4">
              <input required placeholder="Full Name" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newStaff.name} onChange={e => setNewStaff({...newStaff, name: e.target.value})} />
              <input required placeholder="Role" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newStaff.role} onChange={e => setNewStaff({...newStaff, role: e.target.value})} />
              <input required placeholder="Phone" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newStaff.phone} onChange={e => setNewStaff({...newStaff, phone: e.target.value})} />
              <button type="submit" className="w-full py-5 mt-4 bg-indigo-600 text-white rounded-[1.5rem] font-black uppercase shadow-xl">Register Member</button>
            </form>
          </div>
        </div>
      )}

      {isTransportModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 p-4">
          <div className="bg-white p-10 rounded-[2.5rem] w-full max-w-md animate-modalIn relative">
            <button onClick={() => setIsTransportModalOpen(false)} className="absolute top-6 right-6 p-2 text-slate-400 hover:text-slate-900"><X size={24} /></button>
            <h2 className="text-2xl font-black mb-8">New Dispatch</h2>
            <form onSubmit={(e) => { e.preventDefault(); setBusSchedules([...busSchedules, { ...newRoute, id: Date.now().toString(), pickupTime: '06:30 AM', driver: { name: 'Unassigned', phone: '', homeAddress: '', agencyDetails: '' } }]); setIsTransportModalOpen(false); }} className="space-y-4">
              <input required placeholder="Bus ID" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newRoute.busNumber} onChange={e => setNewRoute({...newRoute, busNumber: e.target.value})} />
              <input required placeholder="Route" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold text-sm" value={newRoute.route} onChange={e => setNewRoute({...newRoute, route: e.target.value})} />
              <button type="submit" className="w-full py-5 mt-2 bg-amber-500 text-white rounded-[1.5rem] font-black uppercase shadow-xl">Initialize Route</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

