  // Financial Stats
  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const totalIncome = useMemo(() => income.reduce((acc, curr) => acc + curr.amount, 0), [income]);
  const netProfit = totalIncome - totalExpenses;
  const isProfitable = netProfit >= 0;

  // Combining records for the table with Term/Week awareness
  const allTransactions = useMemo(() => {
    let filteredExpenses = [...expenses];
    if (termFilter !== 'All') {
      filteredExpenses = filteredExpenses.filter(e => e.term === termFilter);
    }
    if (weekFilter !== 'All') {
      filteredExpenses = filteredExpenses.filter(e => e.week === parseInt(weekFilter));
    }

    const combined = [
      ...filteredExpenses.map(e => ({ ...e, type: 'Expense' as const })),
      ...income.map(i => ({ ...i, category: 'General Revenue', description: i.source, type: 'Income' as const, term: 'N/A', week: 'N/A' }))
    ];
    return combined.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [expenses, income, termFilter, weekFilter]);

  const removeTransaction = (id: string, type: 'Income' | 'Expense') => {
    if (window.confirm("Remove this entry permanently?")) {
      if (type === 'Expense') {
        setExpenses(prev => prev.filter(e => e.id !== id));
      } else {
        setIncome(prev => prev.filter(i => i.id !== id));
