            <span>Secure Log Out</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 transition-all duration-300 w-full md:ml-64">
        <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md px-6 py-4 flex justify-between items-center border-b border-slate-100">
          <div className="flex items-center space-x-4">
            <button onClick={() => setIsSidebarOpen(true)} className="md:hidden p-2 text-slate-600"><Menu size={20} /></button>
