              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                <StatCard icon={TrendingUp} label="Treasury" value={`₦${netProfit.toLocaleString()}`} color={netProfit >= 0 ? "bg-emerald-500" : "bg-rose-500"} />
                <StatCard icon={CheckSquare} label="Tasks" value={tasks.filter(t => !t.completed).length.toString()} color="bg-amber-500" />
