// Helper for localStorage
const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    const saved = localStorage.getItem(`pb_portal_${key}`);
    try {
      return saved ? JSON.parse(saved) : defaultValue;
    } catch {
      return defaultValue;
    }
  },
  set: <T,>(key: string, value: T): void => {
    localStorage.setItem(`pb_portal_${key}`, JSON.stringify(value));
  },
  clearAll: (): void => {
    // We clear specifically our app keys to avoid touching other keys if shared domain
    const keys = [
      'pb_portal_auth', 
      'pb_portal_expenses', 
      'pb_portal_income', 
      'pb_portal_inventory', 
      'pb_portal_tasks', 
      'pb_portal_staff', 
      'pb_portal_busSchedules', 
      'pb_portal_aiActivity'
    ];
    keys.forEach(k => localStorage.removeItem(k));
  }
};

