  // Modal Entry States
  const [newExpense, setNewExpense] = useState<{
    amount: number;
    description: string;
    category: string;
    date: string;
    term: 'First Term' | 'Second Term' | 'Third Term';
    week: number;
  }>({ 
    amount: 0, 
    description: '', 
    category: 'Operational', 
    date: new Date().toISOString().split('T')[0],
    term: 'First Term',
    week: 1
  });

  const [newIncome, setNewIncome] = useState({ amount: 0, source: 'School Fees', date: new Date().toISOString().split('T')[0] });
  const [newTask, setNewTask] = useState({ title: '', dueDate: '', priority: 'Medium' as 'Low' | 'Medium' | 'High' });

  // Calculator States
  const [calcDisplay, setCalcDisplay] = useState('0');
  const [calcBuffer, setCalcBuffer] = useState<number | null>(null);
  const [calcOp, setCalcOp] = useState<string | null>(null);

  // Sync with storage
  useEffect(() => {
    storage.set('auth', isAuthenticated);
    if (isAuthenticated) {
      storage.set('expenses', expenses);
      storage.set('income', income);
      storage.set('inventory', inventory);
      storage.set('tasks', tasks);
      storage.set('staff', staff);
      storage.set('busSchedules', busSchedules);
      storage.set('aiActivity', aiActivityLog);
    }
  }, [isAuthenticated, expenses, income, inventory, tasks, staff, busSchedules, aiActivityLog]);

  // Modals
  const [isExpenseModalOpen, setIsExpenseModalOpen] = useState(false);
  const [isIncomeModalOpen, setIsIncomeModalOpen] = useState(false);
  const [isResetModalOpen, setIsResetModalOpen] = useState(false);

  // AI Assistant States
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [aiMessages, setAiMessages] = useState<{role: 'user' | 'assistant', content: string}[]>([
    { role: 'assistant', content: 'Welcome. I am ready to manage Princess Bilingual. I can record expenses, add tasks, or log fees for you. Just tell me what to do!' }
  ]);
  const [aiInput, setAiInput] = useState('');
  const [isAiTyping, setIsAiTyping] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (chatEndRef.current) {
      chatEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [aiMessages]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    // Security Key check
    if (loginForm.username === 'admin' && loginForm.password === 'princess2026') {
      setIsAuthenticated(true);
      setLoginError(false);
    } else {
      setLoginError(true);
      setTimeout(() => setLoginError(false), 1000);
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    storage.set('auth', false);
  };

  const handleReset = () => {
    // Clear state
    setExpenses([]);
    setIncome([]);
    setInventory([]);
    setTasks([]);
    setStaff([]);
    setBusSchedules([]);
    setAiActivityLog([]);
    setTermFilter('All');
    setWeekFilter('All');

    // Clear storage
    storage.clearAll();

    // Close modal
    setIsResetModalOpen(false);

    // Switch to dashboard
    setActiveTab(AppTab.DASHBOARD);

    // Add AI message
    setAiMessages(prev => [...prev, { role: 'assistant', content: 'System has been successfully reset. All records cleared. You can now start with your own data.' }]);
  };

  const totalExpenses = useMemo(() => expenses.reduce((acc, curr) => acc + curr.amount, 0), [expenses]);
  const totalIncome = useMemo(() => income.reduce((acc, curr) => acc + curr.amount, 0), [income]);
  const netProfit = totalIncome - totalExpenses;

  const allTransactions = useMemo(() => {
    let filteredExpenses = [...expenses];
    if (termFilter !== 'All') filteredExpenses = filteredExpenses.filter(e => e.term === termFilter);
    if (weekFilter !== 'All') filteredExpenses = filteredExpenses.filter(e => e.week === parseInt(weekFilter));

    const combined = [
      ...filteredExpenses.map(e => ({ ...e, type: 'Expense' as const })),
      ...income.map(i => ({ ...i, category: 'Revenue', description: i.source, type: 'Income' as const, term: 'N/A', week: 'N/A' }))
    ];
    return combined.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [expenses, income, termFilter, weekFilter]);

  const logAiChange = (tab: AppTab, action: string) => {
    const newLog: AIActivity = {
      id: Date.now().toString(),
      tab,
      action,
      timestamp: new Date().toLocaleString(),
    };
    setAiActivityLog(prev => [newLog, ...prev].slice(0, 20));
  };

  const handleAiChat = async (overrideInput?: string) => {
    const text = overrideInput || aiInput;
    if (!text.trim()) return;
    setAiMessages(prev => [...prev, { role: 'user', content: text }]);
    setAiInput('');
    setIsAiTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: text,
        config: {
          systemInstruction: `You are the Princess Bilingual School AI Assistant. Help the administrator manage school data. Support adding expenses and tasks. Current currency is Naira (₦).`,
          tools: [{ functionDeclarations: aiTools }]
        }
      });

      const textResponse = response.text || "Processed.";
      const functionCalls = response.functionCalls;

      if (functionCalls) {
        for (const fc of functionCalls) {
          if (fc.name === 'addExpense') {
            const args = fc.args as any;
            setExpenses(prev => [...prev, {
              id: `ai-${Date.now()}`,
              amount: args.amount,
              category: args.category || 'Operational',
              description: `[AI] ${args.description}`,
              date: args.date || new Date().toISOString().split('T')[0],
              term: args.term || 'First Term',
              week: args.week || 1
            }]);
            logAiChange(AppTab.EXPENSES, `Recorded expense: ${args.description}`);
          }
          if (fc.name === 'addTask') {
            const args = fc.args as any;
            setTasks(prev => [...prev, {
              id: `ai-${Date.now()}`,
              title: args.title,
              dueDate: args.dueDate || new Date().toISOString().split('T')[0],
              priority: (args.priority || 'Medium') as any,
              completed: false
            }]);
            logAiChange(AppTab.TASKS, `Created task: ${args.title}`);
          }
        }
      }
      setAiMessages(prev => [...prev, { role: 'assistant', content: textResponse }]);
    } catch (e) {
      setAiMessages(prev => [...prev, { role: 'assistant', content: 'Something went wrong. Please check your network connection.' }]);
    } finally {
      setIsAiTyping(false);
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-slate-900 to-black flex items-center justify-center p-4">
        <div className={`w-full max-w-md bg-white/10 backdrop-blur-xl border border-white/20 rounded-[2.5rem] p-8 md:p-12 shadow-2xl transition-all duration-300 ${loginError ? 'animate-shake' : 'animate-fadeIn'}`}>
          <div className="text-center mb-10">
            <div className="inline-flex p-4 bg-indigo-600 rounded-3xl shadow-lg mb-6 shadow-indigo-500/20">
              <Lock className="text-white" size={32} />
            </div>
            <h1 className="text-2xl font-black text-white tracking-tight">Princess Bilingual</h1>
            <p className="text-[10px] text-indigo-300 font-black uppercase tracking-[0.2em] mt-2">Management Portal</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-indigo-200 uppercase tracking-widest ml-4">Username</label>
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-400" size={18} />
                <input 
                  type="text" 
                  value={loginForm.username}
                  onChange={e => setLoginForm({...loginForm, username: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 text-white font-bold outline-none focus:ring-4 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
                  placeholder="admin"
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-indigo-200 uppercase tracking-widest ml-4">Security Key</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-400" size={18} />
                <input 
                  type={showPassword ? "text" : "password"} 
                  value={loginForm.password}
                  onChange={e => setLoginForm({...loginForm, password: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-12 text-white font-bold outline-none focus:ring-4 focus:ring-indigo-500/20 focus:border-indigo-500 transition-all"
                  placeholder="••••••••"
                  required
                />
                <button 
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-indigo-400 hover:text-white"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            <button 
              type="submit"
              className="w-full bg-indigo-600 hover:bg-indigo-500 text-white py-5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-600/20 active:scale-95 transition-all mt-4 flex items-center justify-center space-x-2"
            >
              <span>Unlock Portal</span>
              <ChevronRight size={16} />
            </button>
          </form>

          <p className="text-center text-[10px] text-slate-500 font-bold uppercase mt-10">Authorized Access Only</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-slate-50 overflow-x-hidden relative">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-40 md:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-100 flex flex-col transition-transform duration-300 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0`}>
        <div className="p-6 mb-4 flex justify-between items-center">
          <div>
            <h1 className="text-xl font-black text-indigo-600">Princess Bilingual</h1>
            <p className="text-[9px] text-slate-400 font-black tracking-widest uppercase mt-1">Admin Dashboard</p>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-1 overflow-y-auto scrollbar-hide">
          <SidebarItem icon={LayoutDashboard} label="Dashboard" active={activeTab === AppTab.DASHBOARD} onClick={() => setActiveTab(AppTab.DASHBOARD)} />
          <SidebarItem icon={Wallet} label="Expenses" active={activeTab === AppTab.EXPENSES} onClick={() => setActiveTab(AppTab.EXPENSES)} />
          <SidebarItem icon={Package} label="Inventory" active={activeTab === AppTab.INVENTORY} onClick={() => setActiveTab(AppTab.INVENTORY)} />
          <SidebarItem icon={CheckSquare} label="Tasks" active={activeTab === AppTab.TASKS} onClick={() => setActiveTab(AppTab.TASKS)} />
          <SidebarItem icon={Users} label="Staff" active={activeTab === AppTab.STAFF} onClick={() => setActiveTab(AppTab.STAFF)} />
          <SidebarItem icon={Bus} label="Transport" active={activeTab === AppTab.TRANSPORT} onClick={() => setActiveTab(AppTab.TRANSPORT)} />
          <SidebarItem icon={FileText} label="Policies" active={activeTab === AppTab.POLICIES} onClick={() => setActiveTab(AppTab.POLICIES)} />
        </nav>

        <div className="p-6 mt-auto border-t border-slate-50 space-y-2">
