                <StatCard icon={Activity} label="Total Expenses" value={`₦${totalExpenses.toLocaleString()}`} color="bg-rose-500" />
                <StatCard icon={Calculator} label="Net Balance" value={`₦${netProfit.toLocaleString()}`} color="bg-slate-800" />
              </div>

              <div className="flex flex-wrap items-center gap-4 bg-white p-4 rounded-3xl border border-slate-100 shadow-sm">
                <div className="flex items-center space-x-2 mr-4">
                  <Filter size={16} className="text-slate-400" />
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Filter Records</span>
                </div>
                <select value={termFilter} onChange={e => setTermFilter(e.target.value)} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-indigo-500/20">
                  <option value="All">All Terms</option>
                  <option value="First Term">First Term</option>
                  <option value="Second Term">Second Term</option>
                  <option value="Third Term">Third Term</option>
                </select>
                <select value={weekFilter} onChange={e => setWeekFilter(e.target.value)} className="bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-indigo-500/20">
                  <option value="All">All Weeks</option>
                  {Array.from({length: 11}, (_, i) => i + 1).map(w => <option key={w} value={w}>Week {w}</option>)}
                </select>
                <div className="ml-auto flex space-x-2">
                  <button onClick={() => setIsIncomeModalOpen(true)} className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-emerald-600/20 hover:bg-emerald-500 transition-all active:scale-95">Record Revenue</button>
                  <button onClick={() => setIsExpenseModalOpen(true)} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase shadow-lg shadow-slate-900/20 hover:bg-slate-800 transition-all active:scale-95">Log Expense</button>
                </div>
              </div>

              <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
                <div className="overflow-x-auto scrollbar-hide">
                  <table className="w-full text-left text-xs min-w-[800px]">
                    <thead className="bg-slate-50 text-slate-400 font-black uppercase tracking-widest">
