                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {allTransactions.length === 0 ? (
                        <tr>
                          <td colSpan={6} className="px-6 py-20 text-center text-slate-300 font-black uppercase italic">No financial records found</td>
                        </tr>
                      ) : (
                        allTransactions.map(item => (
                          <tr key={item.id} className="hover:bg-slate-50/80 transition-colors group">
                            <td className="px-6 py-4 font-medium text-slate-500">{item.date}</td>
                            <td className="px-6 py-4 font-black text-slate-400 uppercase text-[9px]">
                              {item.term === 'N/A' ? 'GENERAL' : `${item.term} / W${item.week}`}
                            </td>
                            <td className="px-6 py-4">
                              <span className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase ${item.type === 'Income' ? 'bg-emerald-50 text-emerald-600' : 'bg-indigo-50 text-indigo-600'}`}>{item.category}</span>
                            </td>
                            <td className="px-6 py-4 font-bold text-slate-700">{item.description}</td>
                            <td className={`px-6 py-4 text-right font-black ${item.type === 'Income' ? 'text-emerald-600' : 'text-slate-900'}`}>
                              {item.type === 'Income' ? '+' : '-'}₦{item.amount.toLocaleString()}
