                            <td className="px-6 py-4 text-center">
                              <button 
                                onClick={() => {
                                  if (item.type === 'Expense') setExpenses(expenses.filter(e => e.id !== item.id));
                                  else setIncome(income.filter(i => i.id !== item.id));
                                }}
                                className="p-2 text-slate-300 hover:text-rose-500 transition-colors"
                              >
                                <Trash2 size={16} />
                              </button>
                            </td>
                          </tr>
                        ))
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}

          {/* Placeholder for other tabs to keep app functional */}
          {[AppTab.STAFF, AppTab.INVENTORY, AppTab.TRANSPORT, AppTab.POLICIES, AppTab.TASKS].includes(activeTab) && (
            <div className="bg-white rounded-[2.5rem] p-12 text-center space-y-4 border border-slate-100 shadow-sm animate-fadeIn">
              <div className="inline-flex p-6 bg-indigo-50 text-indigo-600 rounded-3xl mb-4">
                <Activity size={48} />
              </div>
              <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tight">{activeTab} Hub</h2>
