  action: string;
  timestamp: string;
}

// Robust localStorage helper
const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    try {
      const saved = localStorage.getItem(`pb_portal_${key}`);
      if (saved === null) return defaultValue;
      const parsed = JSON.parse(saved);
      // Extra safety for arrays
      if (Array.isArray(defaultValue) && !Array.isArray(parsed)) return defaultValue;
      return parsed;
    } catch (e) {
      console.warn(`Storage fetch error for ${key}:`, e);
      return defaultValue;
    }
  },
  set: <T,>(key: string, value: T): void => {
    try {
      localStorage.setItem(`pb_portal_${key}`, JSON.stringify(value));
    } catch (e) {
      console.error(`Storage save error for ${key}:`, e);
    }
  },
  clearAll: (): void => {
    // To ensure the reset "sticks" and doesn't just reload mocks on refresh,
    // we set the key values to empty arrays instead of just removing them.
    const keys = ['expenses', 'income', 'inventory', 'tasks', 'staff', 'busSchedules', 'aiActivity'];
    keys.forEach(k => storage.set(k, []));
    storage.set('initialized', true); // Flag to show user has moved past mock data
  }
};

