  const [tasks, setTasks] = useState<Task[]>(() => storage.get('tasks', initialTasks));
  const [staff, setStaff] = useState<StaffRecord[]>(() => storage.get('staff', initialStaff));
  const [busSchedules, setBusSchedules] = useState<BusSchedule[]>(() => storage.get('busSchedules', initialBus));
  const [aiActivityLog, setAiActivityLog] = useState<AIActivity[]>(() => storage.get('aiActivity', []));

  // Filters
  const [termFilter, setTermFilter] = useState<string>('All');
  const [weekFilter, setWeekFilter] = useState<string>('All');

  // Modal Entry States
  const [newExpense, setNewExpense] = useState<Omit<Expense, 'id'>>({ 
    amount: 0, 
    description: '', 
    category: 'Operational', 
    date: new Date().toISOString().split('T')[0],
    term: 'First Term',
    week: 1
  });

  const [newIncome, setNewIncome] = useState({ amount: 0, source: 'School Fees', date: new Date().toISOString().split('T')[0] });

  // Sync with storage
  useEffect(() => {
    storage.set('auth', isAuthenticated);
    if (isAuthenticated) {
      storage.set('expenses', expenses);
      storage.set('income', income);
      storage.set('inventory', inventory);
      storage.set('tasks', tasks);
      storage.set('staff', staff);
      storage.set('busSchedules', busSchedules);
      storage.set('aiActivity', aiActivityLog);
    }
  }, [isAuthenticated, expenses, income, inventory, tasks, staff, busSchedules, aiActivityLog]);

