// Ultra-Safe Storage Engine
const storage = {
  get: <T,>(key: string, defaultValue: T): T => {
    try {
      const saved = localStorage.getItem(`pb_portal_v2_${key}`);
      if (saved === null) return defaultValue;
      const parsed = JSON.parse(saved);
      // Ensure we always return an array if the default value is an array
      if (Array.isArray(defaultValue) && !Array.isArray(parsed)) return defaultValue;
      return parsed ?? defaultValue;
    } catch (e) {
      console.warn(`[Storage] Read error for ${key}:`, e);
      return defaultValue;
    }
  },
  set: <T,>(key: string, value: T): void => {
    try {
      localStorage.setItem(`pb_portal_v2_${key}`, JSON.stringify(value));
    } catch (e) {
      console.error(`[Storage] Write error for ${key}:`, e);
    }
  },
  clearEverything: (): void => {
    // Specifically set initialized to true so mocks don't reload
    storage.set('initialized', true);
    const keys = ['expenses', 'income', 'inventory', 'tasks', 'staff', 'busSchedules', 'aiActivity'];
    keys.forEach(k => storage.set(k, []));
  }
};

